package javacode.collectionsapi;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Iterator;

public class CollectionApiExamples {

	public static void main(String[] args) {

		Collection values = new ArrayList();
		values.add(3); values.add("Amresh"); values.add(3.6f);

		//Using Iterator 
		Iterator i =  values.iterator();

		System.out.println("Using Normal SYSOUT");
		//System.out.println(i.next()); System.out.println(i.next()); System.out.println(i.next());	

		System.out.println("Using Normal for loop");
		for(int x =0; x<3; x++) {
			System.out.println(i.next());
		}

		System.out.println("Using Iterator");
		while(i.hasNext()){
			System.out.println(i.next());
		}

		System.out.println("Using Enhanced For loop");
		for(Object j:values) {
			System.out.println(j);
		}

		//Generics Integer
		Collection<Integer> values1 = new ArrayList();
		values1.add(3); values1.add(5); values1.add(3);

		System.out.println("Using Integer Enhanced For loop");
		for(Integer j:values1) {
			System.out.println(j);
		}

	}

}

package javacode.collectionsapi;

import java.util.HashSet;
import java.util.Iterator;
import java.util.Set;

public class HashSetExamples {

	public static void main(String[] args) {

		Set<Integer> hs = new HashSet<Integer>();
		hs.add(23);
		hs.add(45);
		//System.out.println(hs.contains(23));



		Iterator<Integer> it = hs.iterator();

		while(it.hasNext())
		{
			int x = it.next();
			System.out.println(x);
		}

	}

}

